package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private Appendable appendable;

    @BeforeEach
    void setUp() {
        appendable = mock(Appendable.class);
    }

    @Test
    void testPrint_ReturnsCSVPrinter() throws IOException {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);
        assertEquals(appendable, getField(printer, "out"));
        assertEquals(csvFormat, getField(printer, "format"));
    }

    @Test
    void testPrint_WithIOException() throws IOException {
        Appendable throwingAppendable = new Appendable() {
            @Override
            public Appendable append(CharSequence csq) throws IOException {
                throw new IOException("forced");
            }

            @Override
            public Appendable append(char c) throws IOException {
                throw new IOException("forced");
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) throws IOException {
                throw new IOException("forced");
            }
        };
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        // The print method throws IOException from CSVPrinter constructor, so catch it here.
        IOException thrown = assertThrows(IOException.class, () -> csvFormat.print(throwingAppendable));
        assertEquals("forced", thrown.getMessage());
    }

    // Helper method to access private fields via reflection
    private Object getField(Object obj, String fieldName) {
        try {
            Field field = obj.getClass().getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.get(obj);
        } catch (Exception e) {
            fail("Reflection failed: " + e.getMessage());
            return null;
        }
    }
}
